package com.enterprise.auth.exception;

import com.enterprise.auth.dto.ApiResponse;
import org.slf4j.Logger;
import org.slf4j.LoggerFactory;
import org.springframework.http.HttpStatus;
import org.springframework.http.ResponseEntity;
import org.springframework.validation.FieldError;
import org.springframework.web.bind.MethodArgumentNotValidException;
import org.springframework.web.bind.annotation.ExceptionHandler;
import org.springframework.web.bind.annotation.RestControllerAdvice;

import java.util.HashMap;
import java.util.Map;

@RestControllerAdvice
public class GlobalExceptionHandler {

    private static final Logger logger = LoggerFactory.getLogger(GlobalExceptionHandler.class);

    @ExceptionHandler(MfaException.class)
    public ResponseEntity<ApiResponse<String>> handleMfaException(MfaException ex) {
        logger.warn("MFA error: {}", ex.getMessage());
        return ResponseEntity.status(HttpStatus.BAD_REQUEST)
                .body(ApiResponse.error(ex.getMessage()));
    }

    @ExceptionHandler(UserNotFoundException.class)
    public ResponseEntity<ApiResponse<String>> handleUserNotFoundException(UserNotFoundException ex) {
        logger.warn("User not found: {}", ex.getMessage());
        return ResponseEntity.status(HttpStatus.NOT_FOUND)
                .body(ApiResponse.error(ex.getMessage()));
    }

    @ExceptionHandler(BackupCodeExhaustedException.class)
    public ResponseEntity<ApiResponse<String>> handleBackupCodeExhaustedException(BackupCodeExhaustedException ex) {
        logger.warn("Backup codes exhausted: {}", ex.getMessage());
        return ResponseEntity.status(HttpStatus.FORBIDDEN)
                .body(ApiResponse.error(ex.getMessage()));
    }

    @ExceptionHandler(MethodArgumentNotValidException.class)
    public ResponseEntity<ApiResponse<Map<String, String>>> handleValidationExceptions(MethodArgumentNotValidException ex) {
        Map<String, String> errors = new HashMap<>();
        ex.getBindingResult().getAllErrors().forEach((error) -> {
            String fieldName = ((FieldError) error).getField();
            String errorMessage = error.getDefaultMessage();
            errors.put(fieldName, errorMessage);
        });
        return ResponseEntity.status(HttpStatus.BAD_REQUEST)
                .body(ApiResponse.error("Validation failed", errors));
    }

    @ExceptionHandler(IllegalArgumentException.class)
    public ResponseEntity<ApiResponse<String>> handleIllegalArgumentException(IllegalArgumentException ex) {
        logger.warn("Illegal argument: {}", ex.getMessage());
        return ResponseEntity.status(HttpStatus.BAD_REQUEST)
                .body(ApiResponse.error(ex.getMessage()));
    }

    @ExceptionHandler(Exception.class)
    public ResponseEntity<ApiResponse<String>> handleGenericException(Exception ex) {
        logger.error("Unexpected error: ", ex);
        return ResponseEntity.status(HttpStatus.INTERNAL_SERVER_ERROR)
                .body(ApiResponse.error("An unexpected error occurred. Please try again later."));
    }
}

// ==================== Service: BackupCodeService ====================

package com.enterprise.auth.service;

import com.enterprise.auth.dto.BackupCodeStatusResponse;
import com.enterprise.auth.entity.BackupCode;
import com.enterprise.auth.entity.User;
import com.enterprise.auth.exception.BackupCodeExhaustedException;
import com.enterprise.auth.exception.MfaException;
import com.enterprise.auth.repository.BackupCodeRepository;
import org.slf4j.Logger;
import org.slf4j.LoggerFactory;
import org.springframework.beans.factory.annotation.Value;
import org.springframework.security.crypto.password.PasswordEncoder;
import org.springframework.stereotype.Service;
import org.springframework.transaction.annotation.Transactional;

import java.security.SecureRandom;
import java.time.LocalDateTime;
import java.util.ArrayList;
import java.util.List;

@Service
public class BackupCodeService {

    private static final Logger logger = LoggerFactory.getLogger(BackupCodeService.class);
    private static final SecureRandom secureRandom = new SecureRandom();

    private final BackupCodeRepository backupCodeRepository;
    private final PasswordEncoder passwordEncoder;

    @Value("${mfa.backup-codes.count:10}")
    private int backupCodeCount;

    @Value("${mfa.backup-codes.length:8}")
    private int backupCodeLength;

    @Value("${mfa.backup-codes.expiry-days:365}")
    private int backupCodeExpiryDays;

    public BackupCodeService(BackupCodeRepository backupCodeRepository, PasswordEncoder passwordEncoder) {
        this.backupCodeRepository = backupCodeRepository;
        this.passwordEncoder = passwordEncoder;
    }

    @Transactional
    public List<String> generateBackupCodes(User user) {
        logger.info("Generating {} backup codes for user: {}", backupCodeCount, user.getUsername());

        // Delete existing backup codes
        backupCodeRepository.deleteAllByUser(user);

        List<String> plainTextCodes = new ArrayList<>();
        LocalDateTime expiresAt = LocalDateTime.now().plusDays(backupCodeExpiryDays);

        for (int i = 0; i < backupCodeCount; i++) {
            String code = generateSecureCode();
            plainTextCodes.add(code);

            BackupCode backupCode = new BackupCode(
                    passwordEncoder.encode(code),
                    user,
                    expiresAt
            );
            backupCodeRepository.save(backupCode);
        }

        logger.info("Successfully generated {} backup codes for user: {}", backupCodeCount, user.getUsername());
        return plainTextCodes;
    }

    @Transactional
    public boolean verifyBackupCode(User user, String code) {
        if (!user.isMfaEnabled()) {
            throw new MfaException("MFA is not enabled for this user", "MFA_NOT_ENABLED");
        }

        String normalizedCode = normalizeCode(code);
        List<BackupCode> validCodes = backupCodeRepository.findValidBackupCodes(user);

        if (validCodes.isEmpty()) {
            throw new BackupCodeExhaustedException(
                    "No valid backup codes remaining. Please contact your administrator for account recovery."
            );
        }

        for (BackupCode backupCode : validCodes) {
            if (passwordEncoder.matches(normalizedCode, backupCode.getCodeHash())) {
                backupCode.setUsed(true);
                backupCode.setUsedAt(LocalDateTime.now());
                backupCodeRepository.save(backupCode);

                long remaining = backupCodeRepository.countValidBackupCodes(user);
                logger.info("Backup code used for user: {}. Remaining codes: {}", user.getUsername(), remaining);

                if (remaining <= 2) {
                    logger.warn("LOW BACKUP CODES WARNING: User {} has only {} backup codes remaining",
                            user.getUsername(), remaining);
                }

                return true;
            }
        }

        logger.warn("Invalid backup code attempt for user: {}", user.getUsername());
        return false;
    }

    @Transactional
    public List<String> regenerateBackupCodes(User user) {
        if (!user.isMfaEnabled()) {
            throw new MfaException("MFA must be enabled to regenerate backup codes", "MFA_NOT_ENABLED");
        }

        logger.info("Regenerating backup codes for user: {}", user.getUsername());
        return generateBackupCodes(user);
    }

    public BackupCodeStatusResponse getBackupCodeStatus(User user) {
        List<BackupCode> allCodes = backupCodeRepository.findByUserAndUsedFalse(user);
        long validCodes = backupCodeRepository.countValidBackupCodes(user);
        long totalGenerated = user.getBackupCodes().size();
        long usedCodes = totalGenerated - allCodes.size();

        return new BackupCodeStatusResponse(totalGenerated, usedCodes, validCodes);
    }

    @Transactional
    public void revokeAllBackupCodes(User user) {
        logger.info("Revoking all backup codes for user: {}", user.getUsername());
        backupCodeRepository.deleteAllByUser(user);
    }

    private String generateSecureCode() {
        String chars = "ABCDEFGHJKLMNPQRSTUVWXYZ23456789";
        StringBuilder code = new StringBuilder();
        for (int i = 0; i < backupCodeLength; i++) {
            if (i > 0 && i % 4 == 0) {
                code.append('-');
            }
            code.append(chars.charAt(secureRandom.nextInt(chars.length())));
        }
        return code.toString();
    }

    private String normalizeCode(String code) {
        return code.toUpperCase().replaceAll("[\\s-]", "");
    }
}

// ==================== Service: TotpService ====================

package com.enterprise.auth.service;

import org.springframework.stereotype.Service;

import javax.crypto.Mac;
import javax.crypto.spec.SecretKeySpec;
import java.nio.ByteBuffer;
import java.security.InvalidKeyException;
import java.security.NoSuchAlgorithmException;
import java.security.SecureRandom;
import java.util.Base64;

@Service
public class TotpService {

    private static final int CODE_DIGITS = 6;
    private static final int TIME_STEP_SECONDS = 30;
    private static final int ALLOWED_TIME_DRIFT = 1;
    private static final SecureRandom secureRandom = new SecureRandom();
    private static final String ALGORITHM = "HmacSHA1";
    private static final String BASE32_CHARS = "ABCDEFGHIJKLMNOPQRSTUVWXYZ234567";

    public String generateSecret() {
        byte[] secretBytes = new byte[20];
        secureRandom.nextBytes(secretBytes);
        return base32Encode(secretBytes);
    }

    public String generateTotpUri(String secret, String username, String issuer) {
        return String.format("otpauth://totp/%s:%s?secret=%s&issuer=%s&algorithm=SHA1&digits=%d&period=%d",
                issuer, username, secret, issuer, CODE_DIGITS, TIME_STEP_SECONDS);
    }

    public boolean verifyCode(String secret, String code) {
        if (code == null || code.length() != CODE_DIGITS) {
            return false;
        }

        try {
            int codeInt = Integer.parseInt(code);
            long currentTimeStep = System.currentTimeMillis() / 1000 / TIME_STEP_SECONDS;

            for (int i = -ALLOWED_TIME_DRIFT; i <= ALLOWED_TIME_DRIFT; i++) {
                int generatedCode = generateTotpCode(secret, currentTimeStep + i);
                if (generatedCode == codeInt) {
                    return true;
                }
            }
        } catch (NumberFormatException e) {
            return false;
        }

        return false;
    }

    private int generateTotpCode(String secret, long timeStep) {
        byte[] secretBytes = base32Decode(secret);
        byte[] timeBytes = ByteBuffer.allocate(8).putLong(timeStep).array();

        try {
            Mac mac = Mac.getInstance(ALGORITHM);
            mac.init(new SecretKeySpec(secretBytes, ALGORITHM));
            byte[] hash = mac.doFinal(timeBytes);

            int offset = hash[hash.length - 1] & 0x0F;
            int binary = ((hash[offset] & 0x7F) << 24)
                    | ((hash[offset + 1] & 0xFF) << 16)
                    | ((hash[offset + 2] & 0xFF) << 8)
                    | (hash[offset + 3] & 0xFF);

            return binary % (int) Math.pow(10, CODE_DIGITS);
        } catch (NoSuchAlgorithmException | InvalidKeyException e) {
            throw new RuntimeException("Error generating TOTP code", e);
        }
    }

    private String base32Encode(byte[] data) {
        StringBuilder result = new StringBuilder();
        int buffer = 0;
        int bitsLeft = 0;

        for (byte b : data) {
            buffer = (buffer << 8) | (b & 0xFF);
            bitsLeft += 8;
            while (bitsLeft >= 5) {
                result.append(BASE32_CHARS.charAt((buffer >> (bitsLeft - 5)) & 0x1F));
                bitsLeft -= 5;
            }
        }

        if (bitsLeft > 0) {
            result.append(BASE32_CHARS.charAt((buffer << (5 - bitsLeft)) & 0x1F));
        }

        return result.toString();
    }

    private byte[] base32Decode(String encoded) {
        encoded = encoded.toUpperCase().replaceAll("[^A-Z2-7]", "");
        byte[] result = new byte[encoded.length() * 5 / 8];
        int buffer = 0;
        int bitsLeft = 0;
        int index = 0;

        for (char c : encoded.toCharArray()) {
            int val = BASE32_CHARS.indexOf(c);
            if (val < 0) continue;
            buffer = (buffer << 5) | val;
            bitsLeft += 5;
            if (bitsLeft >= 8) {
                result[index++] = (byte) (buffer >> (bitsLeft - 8));
                bitsLeft -= 8;
            }
        }

        return result;
    }
}

