package com.enterprise.auth.controller;

import com.enterprise.auth.dto.*;
import com.enterprise.auth.service.UserService;
import jakarta.servlet.http.HttpServletRequest;
import jakarta.validation.Valid;
import org.springframework.http.ResponseEntity;
import org.springframework.web.bind.annotation.*;

import java.util.List;
import java.util.Map;

@RestController
@RequestMapping("/api/mfa")
public class MfaController {

    private final UserService userService;

    public MfaController(UserService userService) {
        this.userService = userService;
    }

    @PostMapping("/setup/{userId}")
    public ResponseEntity<ApiResponse<MfaSetupResponse>> setupMfa(@PathVariable Long userId) {
        MfaSetupResponse response = userService.initiateMfaSetup(userId);
        return ResponseEntity.ok(ApiResponse.success(
                "MFA setup initiated. Please scan the QR code and save your backup codes securely.", response));
    }

    @PostMapping("/enable")
    public ResponseEntity<ApiResponse<AuthenticationResponse>> enableMfa(
            @Valid @RequestBody EnableMfaRequest request,
            HttpServletRequest httpRequest) {
        String ipAddress = getClientIp(httpRequest);
        String userAgent = httpRequest.getHeader("User-Agent");

        AuthenticationResponse response = userService.enableMfa(request, ipAddress, userAgent);
        return ResponseEntity.ok(ApiResponse.success("MFA enabled successfully", response));
    }

    @PostMapping("/disable/{userId}")
    public ResponseEntity<ApiResponse<Void>> disableMfa(
            @PathVariable Long userId,
            @RequestBody Map<String, String> body,
            HttpServletRequest httpRequest) {
        String password = body.get("password");
        if (password == null || password.isBlank()) {
            return ResponseEntity.badRequest()
                    .body(ApiResponse.error("Password is required to disable MFA"));
        }

        String ipAddress = getClientIp(httpRequest);
        String userAgent = httpRequest.getHeader("User-Agent");

        userService.disableMfa(userId, password, ipAddress, userAgent);
        return ResponseEntity.ok(ApiResponse.success("MFA disabled successfully"));
    }

    @GetMapping("/backup-codes/status/{userId}")
    public ResponseEntity<ApiResponse<BackupCodeStatusResponse>> getBackupCodeStatus(@PathVariable Long userId) {
        BackupCodeStatusResponse status = userService.getBackupCodeStatus(userId);
        return ResponseEntity.ok(ApiResponse.success("Backup code status retrieved", status));
    }

    @PostMapping("/backup-codes/regenerate/{userId}")
    public ResponseEntity<ApiResponse<Map<String, Object>>> regenerateBackupCodes(
            @PathVariable Long userId,
            HttpServletRequest httpRequest) {
        String ipAddress = getClientIp(httpRequest);
        String userAgent = httpRequest.getHeader("User-Agent");

        List<String> newCodes = userService.regenerateBackupCodes(userId, ipAddress, userAgent);

        Map<String, Object> responseData = Map.of(
                "backupCodes", newCodes,
                "totalCodes", newCodes.size(),
                "message", "Please save these codes securely. Previous codes have been invalidated."
        );

        return ResponseEntity.ok(ApiResponse.success(
                "Backup codes regenerated successfully. Previous codes are now invalid.", responseData));
    }

    private String getClientIp(HttpServletRequest request) {
        String xForwardedFor = request.getHeader("X-Forwarded-For");
        if (xForwardedFor != null && !xForwardedFor.isEmpty()) {
            return xForwardedFor.split(",")[0].trim();
        }
        return request.getRemoteAddr();
    }
}

