// ==================== Data Initializer ====================

package com.enterprise.auth.config;

import com.enterprise.auth.entity.User;
import com.enterprise.auth.repository.UserRepository;
import org.slf4j.Logger;
import org.slf4j.LoggerFactory;
import org.springframework.boot.CommandLineRunner;
import org.springframework.context.annotation.Bean;
import org.springframework.context.annotation.Configuration;
import org.springframework.security.crypto.password.PasswordEncoder;

@Configuration
public class DataInitializer {

    private static final Logger logger = LoggerFactory.getLogger(DataInitializer.class);

    @Bean
    public CommandLineRunner initData(UserRepository userRepository, PasswordEncoder passwordEncoder) {
        return args -> {
            if (userRepository.count() == 0) {
                User demoUser = new User("demo", "demo@enterprise.com",
                        passwordEncoder.encode("password123"));
                userRepository.save(demoUser);
                logger.info("Demo user created: username=demo, password=password123");

                User adminUser = new User("admin", "admin@enterprise.com",
                        passwordEncoder.encode("admin123456"));
                userRepository.save(adminUser);
                logger.info("Admin user created: username=admin, password=admin123456");
            }
        };
    }
}